mapper.select:
select *
from course
where id = #{id}
  and teacher_id = #{teacherId}
  and status = 1

mapper.insert:
insert into course(
  id, name, course_code, intro, cover_url, category, teacher_id, status
) values (
  UUID_SHORT(), #{name}, #{courseCode}, #{intro}, #{coverUrl}, #{category}, #{teacherId}, 1
)

mapper.update:
update course
set name = #{name},
    intro = #{intro},
    category = #{category},
    cover_url = #{coverUrl}
where id = #{id}
  and teacher_id = #{teacherId}
  and status = 1

update course
set status = 0,
    deleted_at = now()
where id = #{id}
  and teacher_id = #{teacherId}
  and status = 1
